import * as React from "react";

import DownloadIcon from "../icons/DownloadIcon";
import LoadingIcon from "../icons/LoadingIcon";
import { cn } from "../utils/cn";

type DownloadButtonProps = {
  /** Called when the user selects "CSV" from the dropdown. */
  onDownloadCsv?: () => void;
  /** Called when the user selects "Excel" from the dropdown. */
  onDownloadExcel?: () => void;
  /** Whether a download is currently in progress (shows spinner). */
  loading?: boolean;
  /** Tooltip text. */
  tooltip?: string;
  className?: string;
};

/**
 * A download icon button matching the Vue V2 Download.vue component.
 *
 * Renders as a 45px x 44px bordered icon button. Clicking opens a dropdown
 * menu with "CSV" and "Excel" options. When `loading` is true, a spinner
 * replaces the download icon.
 *
 * Vue reference:
 * - Width: 45px, Height: 44px
 * - White background, border brand-grey-400, border-radius 4px
 * - Dropdown with "Table data" header, CSV and Excel items
 */
function DownloadButton({
  onDownloadCsv,
  onDownloadExcel,
  loading = false,
  tooltip = "Download data",
  className,
}: DownloadButtonProps) {
  const [open, setOpen] = React.useState(false);
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  React.useEffect(() => {
    if (!open) return;

    function handleClickOutside(event: MouseEvent) {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target as Node)
      ) {
        setOpen(false);
      }
    }

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [open]);

  return (
    <div
      ref={containerRef}
      className="relative inline-block"
      data-slot="download-button"
    >
      <button
        type="button"
        disabled={loading}
        onClick={() => setOpen((prev) => !prev)}
        title={tooltip}
        aria-label={tooltip}
        aria-expanded={open}
        aria-haspopup="menu"
        className={cn(
          "inline-flex h-[44px] w-[45px] items-center justify-center rounded border border-brand-grey-400 bg-white",
          "transition-colors hover:bg-gray-50",
          "disabled:pointer-events-none disabled:opacity-50",
          className,
        )}
      >
        {loading ? (
          <LoadingIcon size="sm" className="animate-spin" />
        ) : (
          <DownloadIcon size="md" className="text-brand-grey-800" />
        )}
      </button>

      {/* Dropdown menu */}
      {open && (
        <div
          role="menu"
          className="absolute right-0 top-full z-50 mt-1 min-w-[140px] rounded border border-border bg-white shadow-md"
        >
          <div className="px-3 py-1.5 text-xs font-medium text-muted-foreground">
            Table data
          </div>
          <div className="h-px bg-border" />
          <button
            type="button"
            role="menuitem"
            className="flex w-full items-center px-3 py-2 text-sm hover:bg-accent"
            onClick={() => {
              onDownloadCsv?.();
              setOpen(false);
            }}
          >
            CSV
          </button>
          <button
            type="button"
            role="menuitem"
            className="flex w-full items-center px-3 py-2 text-sm hover:bg-accent"
            onClick={() => {
              onDownloadExcel?.();
              setOpen(false);
            }}
          >
            Excel
          </button>
        </div>
      )}
    </div>
  );
}

export { DownloadButton };
export type { DownloadButtonProps };
